import Foundation

final class APIClient: ObservableObject {
    @Published var apiResponse: String = ""
    @Published var legacyResponse: String = ""
    @Published var isLoading = false
    @Published var errorMessage: String?

    private let session: URLSession = {
        let configuration = URLSessionConfiguration.default
        configuration.waitsForConnectivity = true
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        return URLSession(configuration: configuration)
    }()

    func fetchAll() {
        isLoading = true
        errorMessage = nil

        let group = DispatchGroup()

        group.enter()
        fetch(from: "https://api.example.com") { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let value):
                    self?.apiResponse = value
                case .failure(let error):
                    self?.errorMessage = error.localizedDescription
                }
                group.leave()
            }
        }

        group.enter()
        fetch(from: "http://legacy.internal") { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let value):
                    self?.legacyResponse = value
                case .failure(let error):
                    self?.errorMessage = error.localizedDescription
                }
                group.leave()
            }
        }

        group.notify(queue: .main) { [weak self] in
            self?.isLoading = false
        }
    }

    private func fetch(from urlString: String, completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: urlString) else {
            completion(.failure(NSError(domain: "InvalidURL", code: -1)))
            return
        }

        let task = session.dataTask(with: url) { data, response, error in
            if let error {
                completion(.failure(error))
                return
            }

            if let httpResponse = response as? HTTPURLResponse,
               !(200...299).contains(httpResponse.statusCode) {
                completion(.failure(NSError(domain: "HTTPError", code: httpResponse.statusCode)))
                return
            }

            let text = data.flatMap { String(data: $0, encoding: .utf8) } ?? "No content"
            completion(.success(text))
        }

        task.resume()
    }
}

